//
// Hand-authored regression test for the after-id (keyset) pagination fallback
// added in response to issue #88: NinjaOne list endpoints (/v2/devices, ...)
// return a bare JSON array and paginate via ?after=<lastEntityId>. The sync
// loop previously stopped at the first full page and reported a truncated
// dataset as complete. These tests lock the two helpers that drive the fix.
// NOT generated by the Printing Press — do not overwrite on reprint.

package cli

import (
	"encoding/json"
	"testing"
)

func TestIsBareArrayResponse(t *testing.T) {
	cases := []struct {
		name string
		body string
		want bool
	}{
		{"bare array of objects", `[{"id":1},{"id":2}]`, true},
		{"empty array", `[]`, true},
		{"object envelope with cursor (queries shape)", `{"cursor":{"name":"abc"},"results":[{"id":1}]}`, false},
		{"object envelope with items", `{"items":[{"id":1}]}`, false},
		{"json null", `null`, false},
		{"single object", `{"id":1}`, false},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			if got := isBareArrayResponse(json.RawMessage(tc.body)); got != tc.want {
				t.Fatalf("isBareArrayResponse(%s) = %v, want %v", tc.body, got, tc.want)
			}
		})
	}
}

func TestExtractLastItemID(t *testing.T) {
	cases := []struct {
		name   string
		items  []string
		wantID string
		wantOK bool
	}{
		{"numeric id picks the LAST item", []string{`{"id":1}`, `{"id":1000}`}, "1000", true},
		{"large integer id is not float-rounded", []string{`{"id":55043301}`}, "55043301", true},
		{"string id", []string{`{"id":"dev-7"}`}, "dev-7", true},
		{"uid fallback when no id", []string{`{"uid":"u-42"}`}, "u-42", true},
		{"no usable id field", []string{`{"name":"x"}`}, "", false},
		{"zero id is rejected (cannot advance)", []string{`{"id":0}`}, "", false},
		{"empty page", []string{}, "", false},
		{"scalar item (not an object)", []string{`123`}, "", false},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			items := make([]json.RawMessage, 0, len(tc.items))
			for _, it := range tc.items {
				items = append(items, json.RawMessage(it))
			}
			gotID, gotOK := extractLastItemID(items)
			if gotID != tc.wantID || gotOK != tc.wantOK {
				t.Fatalf("extractLastItemID(%v) = (%q, %v), want (%q, %v)", tc.items, gotID, gotOK, tc.wantID, tc.wantOK)
			}
		})
	}
}
